function replaceAllLiteral(input, source, target) {
  return input.split(source).join(target);
}

function localisePage(source, locale, file) {
  let html = source.replace('<html lang="nl">', `<html lang="${locale}">`);

  for (const [from, to] of Object.entries(translations[locale]).sort(([a], [b]) => b.length - a.length)) {
    if (from !== to) html = replaceAllLiteral(html, from, to);
  }

  html = html.replaceAll('assets/', '../assets/');

  const labels = locale === "fr"
    ? { nav: "Choisir la langue", nl: "Néerlandais", fr: "Français", en: "Anglais" }
    : { nav: "Choose language", nl: "Dutch", fr: "French", en: "English" };
  const switcher = locale === "fr"
    ? `<nav class="lang-switch" aria-label="${labels.nav}"><a href="../${file}" lang="nl" aria-label="${labels.nl}">NL</a><a class="active" href="${file}" lang="fr" aria-current="page" aria-label="${labels.fr}">FR</a><a href="../en/${file}" lang="en" aria-label="${labels.en}">EN</a></nav>`
    : `<nav class="lang-switch" aria-label="${labels.nav}"><a href="../${file}" lang="nl" aria-label="${labels.nl}">NL</a><a href="../fr/${file}" lang="fr" aria-label="${labels.fr}">FR</a><a class="active" href="${file}" lang="en" aria-current="page" aria-label="${labels.en}">EN</a></nav>`;

  html = html.replace(/<nav class="lang-switch"[\s\S]*?<\/nav>/, switcher);
  html = html.replace(/main\.min\.js\?v=\d+/g, "main.min.js?v=8");
  return html;
}

for (const locale of ["fr", "en"]) {
  const outputDir = path.join(root, locale);
  fs.mkdirSync(outputDir, { recursive: true });
  for (const file of pages) {
    const source = fs.readFileSync(path.join(root, file), "utf8");
    fs.writeFileSync(path.join(outputDir, file), localisePage(source, locale, file), "utf8");
  }
}

